+  errValue: E, maybes?: Iterable<Maybe<T>>
+): Result<T[], E> | ((maybes: Iterable<Maybe<T>>) => Result<T[], E>) {
+  if (maybes === undefined) return (items) => sequenceMaybeAsResult(errValue, items);
+  const values: T[] = [];
+  for (const maybe of maybes) {
+    if (maybe.isNothing) return Result.err(errValue);
+    values.push(maybe.value);
+  }
+  return Result.ok(values);
