+
+/** Map and collect `Maybe`s, treating `Nothing` as the supplied error. */
+export function traverseMaybeAsResult<T, U extends {}, E>(
+  errValue: E, items: Iterable<T>, fn: (item: T) => Maybe<U>
+): Result<U[], E>;
+export function traverseMaybeAsResult<T, U extends {}, E>(
+  errValue: E
+): (items: Iterable<T>, fn: (item: T) => Maybe<U>) => Result<U[], E>;
+export function traverseMaybeAsResult<T, U extends {}, E>(
+  errValue: E, items?: Iterable<T>, fn?: (item: T) => Maybe<U>
+): Result<U[], E> | ((items: Iterable<T>, fn: (item: T) => Maybe<U>) => Result<U[], E>) {
+  if (items === undefined || fn === undefined) {
+    return (remainingItems, remainingFn) => traverseMaybeAsResult(errValue, remainingItems, remainingFn);
+  }
+  const values: U[] = [];
+  for (const item of items) {
+    const maybe = fn(item);
+    if (maybe.isNothing) return Result.err(errValue);
+    values.push(maybe.value);
+  }
+  return Result.ok(values);
+}
+
