+
+describe('collection composition', () => {
+  test('Maybe and Result are iterable only on success', () => {
+    expect([...maybe.just(1)]).toEqual([1]);
+    expect([...maybe.nothing<number>()]).toEqual([]);
+    expect([...result.ok(1)]).toEqual([1]);
+    expect([...result.err<number, string>('no')]).toEqual([]);
+  });
+
+  test('Maybe sequence and traverse stop iterating after Nothing', () => {
+    let advanced = 0;
+    function* values() {
+      yield maybe.just(1);
+      yield maybe.nothing<number>();
+      advanced += 1;
+      yield maybe.just(3);
+    }
+    expect(maybe.sequence(values())).toEqual(maybe.nothing());
+    expect(advanced).toBe(0);
+    expect(maybe.traverse([1, 2, 3], (n) => (n === 2 ? maybe.nothing() : maybe.just(n)))).toEqual(
+      maybe.nothing()
+    );
+    expect(maybe.compact([maybe.just(1), maybe.nothing(), maybe.just(3)])).toEqual([1, 3]);
+    expect(maybe.filterMap([1, 2, 3], (n) => (n % 2 ? maybe.just(n) : maybe.nothing()))).toEqual([1, 3]);
+    expect(maybe.firstJust([maybe.nothing(), maybe.just(2)])).toEqual(maybe.just(2));
+  });
+
+  test('Result collection helpers preserve the first failure', () => {
+    expect(result.sequence([result.ok(1), result.err('no'), result.ok(3)])).toEqual(result.err('no'));
