+import { describe, expect, test } from 'vitest';
+
+import * as maybe from 'true-myth/maybe';
+import * as result from 'true-myth/result';
+import Task, * as task from 'true-myth/task';
+import * as toolbelt from 'true-myth/toolbelt';
+
+describe('collection composition', () => {
+  test('Maybe and Result are iterable only on success', () => {
+    expect([...maybe.just(1)]).toEqual([1]);
+    expect([...maybe.nothing<number>()]).toEqual([]);
+    expect([...result.ok(1)]).toEqual([1]);
+    expect([...result.err<number, string>('no')]).toEqual([]);
+  });
+
+  test('Maybe sequence and traverse stop iterating after Nothing', () => {
+    let advanced = 0;
+    function* values() {
+      yield maybe.just(1);
+      yield maybe.nothing<number>();
+      advanced += 1;
+      yield maybe.just(3);
+    }
+    expect(maybe.sequence(values())).toEqual(maybe.nothing());
+    expect(advanced).toBe(0);
+    expect(maybe.traverse([1, 2, 3], (n) => (n === 2 ? maybe.nothing() : maybe.just(n)))).toEqual(
+      maybe.nothing()
+    );
+    expect(maybe.compact([maybe.just(1), maybe.nothing(), maybe.just(3)])).toEqual([1, 3]);
+    expect(maybe.filterMap([1, 2, 3], (n) => (n % 2 ? maybe.just(n) : maybe.nothing()))).toEqual([1, 3]);
+    expect(maybe.firstJust([maybe.nothing(), maybe.just(2)])).toEqual(maybe.just(2));
+  });
+
+  test('Result collection helpers preserve the first failure', () => {
+    expect(result.sequence([result.ok(1), result.err('no'), result.ok(3)])).toEqual(result.err('no'));
+    expect(result.zipWith(result.ok(2), result.ok(3), (a, b) => a + b)).toEqual(result.ok(5));
+    expect(result.partition([result.ok(1), result.err('no'), result.ok(3)])).toEqual([[1, 3], ['no']]);
+  });
+
+  test('Task async iteration, serial traversal, taps, and retries retain outcomes', async () => {
+    expect(await Array.fromAsync(Task.resolve(1))).toEqual([result.ok(1)]);
+    expect(await Array.fromAsync(Task.reject<number, string>('no'))).toEqual([result.err('no')]);
+    const started: number[] = [];
+    expect(await task.traverseSerial([1, 2, 3], (n) => {
+      started.push(n);
+      return n === 2 ? Task.reject('no') : Task.resolve(n);
+    })).toEqual(result.err('no'));
+    expect(started).toEqual([1, 2]);
+    const seen: number[] = [];
+    expect(await task.tap(Task.resolve(1), (n) => seen.push(n))).toEqual(result.ok(1));
+    expect(seen).toEqual([1]);
+    let attempts = 0;
+    expect(await task.retryN(2, () => (++attempts < 3 ? Task.reject('no') : Task.resolve(3)))).toEqual(result.ok(3));
+    expect(attempts).toBe(3);
+  });
+
+  test('toolbelt converts Nothing to the caller supplied error', () => {
+    expect(toolbelt.sequenceMaybeAsResult('missing', [maybe.just(1), maybe.nothing()])).toEqual(result.err('missing'));
+    expect(toolbelt.traverseMaybeAsResult('missing', [1, 2], (n) => n === 2 ? maybe.nothing() : maybe.just(n))).toEqual(result.err('missing'));
+    expect(toolbelt.zipMaybeAsResult('missing', maybe.just(1), maybe.just(2))).toEqual(result.ok([1, 2]));
+  });
+});
